from rebar._store.canonical import content_hash as _content_hash

def change_fingerprint(change_id: str, revision: str, changed_files: list[str], diff_text: str) -> str:
    basis = {"change_id": change_id, "revision": revision, "changed_files": sorted(changed_files), "diff_sha": hashlib.sha256(diff_text.encode()).hexdigest()}
    return _content_hash(basis)[:16]
